type AppSettingSummary = { label: string; total: number; readOnly: number }

const appSettingColumns: HarmonyColumn<AppSetting, AppSettingSummary>[] = [
  {
    key: 'key',
    header: 'Key',
    width: 220,
    frozen: true,
    renderCell: ({ row }) => (
      <span className="font-mono text-xs font-semibold text-foreground">{row.key}</span>
    ),
    renderSummaryCell: ({ row }) => (
      <span className="text-xs font-bold text-muted-foreground">{row.label}</span>
    ),
  },
  {
    key: 'category',
    header: 'Category',
    width: 150,
    renderCell: ({ row }) =>
      row.category ? (
        <Badge variant="outline" className="text-[10px] font-semibold">{row.category}</Badge>
      ) : (
        <span className="text-muted-foreground text-xs italic">—</span>
      ),
    renderSummaryCell: ({ row }) => (
      <span className="text-xs text-muted-foreground tabular-nums">{row.total} total</span>
    ),
  },
  {
    key: 'value',
    header: 'Value',
    width: 220,
    renderCell: ({ row }) => (
      <span className={`font-mono text-xs ${row.value ? 'text-foreground' : 'text-muted-foreground italic'}`}>
        {row.value ?? 'null'}
      </span>
    ),
  },
  {
    key: 'description',
    header: 'Description',
    renderCell: ({ row }) => (
      <span className="text-xs text-muted-foreground line-clamp-1">
        {row.description ?? '—'}
      </span>
    ),
  },
  {
    key: 'isReadOnly',
    header: 'Read Only',
    width: 110,
    renderCell: ({ row }) =>
      row.isReadOnly ? (
        <span className="flex items-center gap-1.5 text-xs text-amber-600 font-medium">
          <Lock size={11} /> Yes
        </span>
      ) : (
        <span className="flex items-center gap-1.5 text-xs text-muted-foreground">
          <CheckCircle size={11} /> No
        </span>
      ),
    renderSummaryCell: ({ row }) => (
      <span className="text-xs text-amber-600 font-semibold tabular-nums">{row.readOnly} read-only</span>
    ),
  },
]

function AppSettingsTableDemo() {
  const [selectedRows,    setSelectedRows]    = useState<ReadonlySet<string | number>>(new Set())
  const [editTarget,      setEditTarget]      = useState<AppSetting | null>(null)
  const [deleteTarget,    setDeleteTarget]    = useState<AppSetting | null>(null)
  const [bulkDeleteOpen,  setBulkDeleteOpen]  = useState(false)
  const [bulkExportOpen,  setBulkExportOpen]  = useState(false)
  const [autoRefresh,     setAutoRefresh]     = useState(false)
  const [refreshInterval, setRefreshInterval] = useState(30)

  const { data, isLoading, isError, refetch, isFetching } = useQuery({
    queryKey: ['showcase-app-settings'],
    queryFn: () => appSettingsService.getAppSettings(1, 500),
    retry: false,
    staleTime: 30_000,
  })

  const summaryRowsFn = (filtered: AppSetting[]): AppSettingSummary[] => [
    { label: 'Summary', total: filtered.length, readOnly: filtered.filter(r => r.isReadOnly).length },
  ]

  const actionsColumn: HarmonyColumn<AppSetting, AppSettingSummary> = {
    key: 'actions',
    header: 'Actions',
    width: 80,
    sortable: false,
    resizable: false,
    cellClass: 'rdg-cell-actions',
    renderCell: ({ row }) => (
      <div className="flex items-center gap-0.5">
        <Button
          size="icon-xs"
          variant="ghost"
          className="hover:bg-primary/10 hover:text-primary"
          onClick={() => setEditTarget(row)}
        >
          <Pencil size={12} />
        </Button>
        <Button
          size="icon-xs"
          variant="ghost"
          className="text-destructive hover:text-destructive hover:bg-destructive/10"
          onClick={() => setDeleteTarget(row)}
        >
          <Trash2 size={12} />
        </Button>
      </div>
    ),
  }

  return (
    <>
      <HarmonyTable<AppSetting, AppSettingSummary>
        rows={data?.data ?? []}
        columns={[...appSettingColumns, actionsColumn]}
        rowKeyGetter={row => row.id}
        loading={isLoading}

        title="Application Settings"
        description="Live data from /api/application-settings — requires Admin auth"

        searchable
        searchPlaceholder="Filter settings…"

        dataActions={{
          onCreate:  () => {},
          createLabel: 'New Setting',
          onReload:  () => refetch(),
          reloading: isFetching,
          onExport:  () => setBulkExportOpen(true),
          autoRefresh: {
            enabled:  autoRefresh,
            interval: refreshInterval,
            onToggle: setAutoRefresh,
            onIntervalChange: setRefreshInterval,
          },
        }}

        selectable
        selectedRows={selectedRows}
        onSelectedRowsChange={setSelectedRows}

        selectionActions={(keys) => (
          <>
            <Button size="xs" variant="outline" onClick={() => setBulkExportOpen(true)}>
              <Download size={12} /> Export
            </Button>
            <Button
              size="xs"
              variant="destructive"
              onClick={() => setBulkDeleteOpen(true)}
            >
              <Trash2 size={12} /> Delete {keys.size}
            </Button>
          </>
        )}

        pagination={{ pageSize: 25 }}

        bottomSummaryRowsFn={data ? summaryRowsFn : undefined}

        emptyMessage={
          isError
            ? 'Could not load data — log in as Admin to view application settings'
            : 'No settings found'
        }

        draggableColumns
        striped
      />

      {/* ── Row-level dialogs ─────────────────────────────────────────────── */}
      <HarmonyAlertDialog
        open={editTarget !== null}
        onOpenChange={open => { if (!open) setEditTarget(null) }}
        title="Edit Setting"
        description={editTarget ? `Editing "${editTarget.key}". This is a UI demo — no changes will be saved.` : undefined}
        actionLabel="Save Changes"
        onAction={() => setEditTarget(null)}
      />
      <HarmonyAlertDialog
        open={deleteTarget !== null}
        onOpenChange={open => { if (!open) setDeleteTarget(null) }}
        variant="danger"
        title="Delete Setting"
        description={deleteTarget ? `"${deleteTarget.key}" will be permanently deleted. This action cannot be undone.` : undefined}
        actionLabel="Delete"
        onAction={() => setDeleteTarget(null)}
      />

      {/* ── Bulk action dialogs ───────────────────────────────────────────── */}
      <HarmonyAlertDialog
        open={bulkExportOpen}
        onOpenChange={setBulkExportOpen}
        title={`Export ${selectedRows.size} Settings`}
        description="The selected settings will be exported as a JSON file. This is a UI demo — no file will be generated."
        actionLabel="Export"
        onAction={() => setBulkExportOpen(false)}
      />
      <HarmonyAlertDialog
        open={bulkDeleteOpen}
        onOpenChange={setBulkDeleteOpen}
        variant="danger"
        title={`Delete ${selectedRows.size} Settings`}
        description="The selected settings will be permanently deleted. This action cannot be undone."
        actionLabel="Delete"
        onAction={() => { setBulkDeleteOpen(false); setSelectedRows(new Set()) }}
      />
    </>
  )
}

